html.script:
setTimeout(function() {
  // Apply thresholding for Data Hygiene value text
  var hygieneValue = document.getElementById('hygiene-value');
  if (hygieneValue) {
    var hygieneVal = parseFloat(hygieneValue.textContent);
    if (hygieneVal >= 70) {
      hygieneValue.classList.add('good');
    } else if (hygieneVal >= 50) {
      hygieneValue.classList.add('warning');
    } else {
      hygieneValue.classList.add('critical');
    }
  }
  
  // Apply thresholding for Total Optimization value text
  var optValue = document.getElementById('opt-value');
  if (optValue) {
    var optVal = parseFloat(optValue.textContent);
    if (optVal >= 40) {
      optValue.classList.add('good');
    } else if (optVal >= 20) {
      optValue.classList.add('warning');
    } else {
      optValue.classList.add('critical');
    }
  }
}, 1000);
